import React, { useEffect, useState } from "react";
import { getDashboardSummary } from "./api";
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell,
} from "recharts";

function App() {
  const [data, setData] = useState(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const res = await getDashboardSummary();
      console.log("SUMMARY:", res);
      setData(res);
    } catch (err) {
      console.error("API ERROR:", err);
    }
  };

  if (!data) return <h2 style={{ color: "white" }}>Loading...</h2>;

  // Convert data for charts
  const batchData = Object.keys(data.batch_revenue).map((key) => ({
    name: key,
    value: data.batch_revenue[key],
  }));

  const modeData = Object.keys(data.mode_distribution).map((key) => ({
    name: key,
    value: data.mode_distribution[key],
  }));

  const COLORS = ["#0088FE", "#FF8042"];

  return (
    <div style={{ padding: 20, color: "white", background: "#0b1220", minHeight: "100vh" }}>
      <h1>Payments Dashboard</h1>

      {/* KPI */}
      <div style={{ display: "flex", gap: 40, marginTop: 20 }}>
        <div>
          <h2>₹ {data.total_revenue.toLocaleString()}</h2>
          <p>Total Revenue</p>
        </div>

        <div>
          <h2>{data.total_students}</h2>
          <p>Total Students</p>
        </div>
      </div>

      {/* Charts */}
      <div style={{ display: "flex", gap: 50, marginTop: 50 }}>
        
        {/* Batch Revenue */}
        <div style={{ width: "50%", height: 350 }}>
          <h3>Revenue by Batch</h3>
          <ResponsiveContainer>
            <BarChart data={batchData}>
              <XAxis dataKey="name" />
              <YAxis />
              <Tooltip />
              <Bar dataKey="value" />
            </BarChart>
          </ResponsiveContainer>
        </div>

        {/* Mode Distribution */}
        <div style={{ width: "50%", height: 350 }}>
          <h3>Mode Distribution</h3>
          <ResponsiveContainer>
            <PieChart>
              <Pie
                data={modeData}
                dataKey="value"
                nameKey="name"
                outerRadius={120}
                label
              >
                {modeData.map((entry, index) => (
                  <Cell key={index} fill={COLORS[index % COLORS.length]} />
                ))}
              </Pie>
              <Tooltip />
            </PieChart>
          </ResponsiveContainer>
        </div>

      </div>
    </div>
  );
}

export default App;